var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"합중국, 롱 혼 자치구 – 16:42:07\\n마리아 안토노프 중장, <color=#ffd34c>만타레이 교도소 면회실</color>\\nCSE Lv. <b>0</b>","JPN":"合衆国、ロング・ホーン自治区　–　16:42:07\\nマリア・アントノフ中将、<color=#ffd34c>マンタレー刑務所面会室</color>\\nCSE Lv.<b>0</b>","ENG":"The States, Long Horn Autonomous Region – 16:42:07\\nLieutenant General Maria Antonov, <color=#ffd34c>Manta Ray Prison Visiting Room</color>\\nCSE Lv. <b>0</b>","TWN":"合眾國 倫霍恩自治區 – 16:42:07\\n瑪麗亞·安東諾夫中將，<color=#ffd34c>曼塔雷監獄接見室</color>\\nCSE Lv. <b>0</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"수감 번호 1677번. 면회다.","JPN":"囚人番号1677番。面会だ。","ENG":"Prisoner #1677, you have a visitor.","TWN":"1677，有人來見你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L4_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"수감 번호 1677번! 면회다! 즉시 일어서서 벽을 바라보고 서라!","JPN":"囚人番号1677番！　面会だ！　今すぐ壁を向いて立て！","ENG":"Prisoner #1677! You have a visitor! Stand up and face the wall right now!","TWN":"1677！立刻起來面壁站好！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"그렇지 않으면……","JPN":"さもなければ……","ENG":"Or else...","TWN":"否則……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 괜찮아. 그보다 둘만 있게 해 주게.","JPN":"いや、いいんだ。それより二人きりにしてくれ。","ENG":"It’s quite alright. Leave us.","TWN":"沒關係，你先退下，留我們兩個就好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"하지만 중장님, 아시다시피 수감 번호 1677번은…….","JPN":"しかし中将、ご存知のとおり囚人番号1677番は……","ENG":"But Lieutenant General, as you know, Prisoner #1677 is...","TWN":"可是中將您也知道1677她……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮다고 했네. 날 믿지 못하는 건가?","JPN":"いいと言ったはずだ。それとも、私のことが信用できないのか？","ENG":"I said it’s okay. Is there a problem?","TWN":"我說了沒關係，你現在是在質疑我？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"……그럴 리가요. 부디 조심하십시오.","JPN":"……とんでもありません。どうかお気をつけください。","ENG":"No, ma’am. Please be careful.","TWN":"……不敢！那請中將務必小心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"고맙네.","JPN":"ありがとう。","ENG":"Thank you.","TWN":"謝謝。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"잘 지냈나, 제이나.","JPN":"元気にしていたか、ジェイナ。","ENG":"How have you been, Jaina?","TWN":"婕娜，你好嗎？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"안색이 많이 나쁘군. 혹시 그 사이 새로운 기억이라도 떠오른 건가.","JPN":"顔色が悪いな。\\nもしや、何か新しい記憶を思い出したのか？","ENG":"You don’t look well. Some new memory come up?","TWN":"你的臉色不太好，又有新的記憶浮現嗎？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……네, 안토노프 <color=#ffd34c>대령</color>님.","JPN":"……はい、アントノフ<color=#ffd34c>大佐</color>。","ENG":"Yes, <color=#ffd34c>Colonel</color> Antonov.","TWN":"……是的，安東諾夫 <color=#ffd34c>上校</color>。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋았던 시절이 생각 나는 호칭이로군.","JPN":"古き良き時代を思い出させる呼び名だな。","ENG":"“Colonel”, that reminds me of the good old days.","TWN":"這個稱呼令我想起過去美好的時光呢。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전황은 어려웠고 힘든 일도 많았지만, 젊은 혈기에 나름 희망도 있었고…….","JPN":"戦況は厳しく、大変なことも多かったが、まだ若かった頃で希望も残っていたな……","ENG":"The war was tough, but I was young and hopeful back then...","TWN":"雖然戰況很艱難、很辛苦，但是因為年輕氣盛，所以還是滿懷著希望……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"무엇보다 목숨을 맡길 수 있는 동료들이 곁에 있었지.","JPN":"何より、傍には命を預けられる仲間たちがいた。","ENG":"And I also had comrades that I could rely on.","TWN":"更重要的是，身旁有一群可以同生共死的夥伴。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 지금은 그저 은퇴할 날만 기다리는 늙은이야.","JPN":"今は引退する日を待つばかりの老いぼれだがな。","ENG":"But now I’m nothing but an old woman who’s waiting for retirement.","TWN":"但現在的我就只是個快要退休的老人。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"당신이 준 책을 읽다가 떠올랐어요.","JPN":"あなたから頂いた本を読んで思い出しました。","ENG":"It came up when I was reading the book you sent me.","TWN":"我看了你給我的書後想起來了。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그 사람</color>이, 당신을 얼마나 믿고 있었는지도.","JPN":"<color=#ffd34c>あの人</color>があなたのことをどれほど信頼していたかを。","ENG":"How much <color=#ffd34c>he</color> trusted you back then.","TWN":"<color=#ffd34c>那個人</color>當時有多信任你。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나도 도미닉을 믿고 있었어.","JPN":"私もドミニークを信頼していたさ。","ENG":"I trusted Dominic as well.","TWN":"我也很信任多明尼克。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그는 내가 가장 신뢰하는 동료, 아니 친구였지. 이제는 그럴 수 없게 되었네만.","JPN":"彼は私が最も信頼する同僚、いや、友だった。\\nもうそうではなくなってしまったが。","ENG":"He was my most trusted comrade—no, friend. Although he can’t be either now.","TWN":"他是我最信任的夥伴，不，應該說是朋友，雖然現在人事已非。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"도미닉이란 사람은……. 리플레이서 퀸에게 어떤 의미였나요?","JPN":"ドミニークという人は……リプレイサー・クイーンにとって、どんな存在でしたか？","ENG":"So this Dominic... What was he to the Replacer Queen?","TWN":"那個叫多明尼克的人……對克隆·女皇的意義是什麼？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"군인 출신의 테러리스트.","JPN":"軍人出身のテロリスト。","ENG":"A terrorist who used to be a soldier.","TWN":"是軍人出身的恐怖份子。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내가 해 줄 수 있는 대답은 그것뿐이라네.","JPN":"私に言えることはそれだけだ。","ENG":"That’s all I can say.","TWN":"我能告訴你的就這麼多。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>저</color>는, 그런 흉악범과 조금이라도 연관되길 원치 않아요.","JPN":"<color=#ffd34c>私</color>は、そんな凶悪犯とは少しも関わりたくありません。","ENG":"<color=#ffd34c>I</color> don’t want to be connected to that criminal.","TWN":"<color=#ffd34c>我</color>一點都不想和那種惡人扯上關係。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그런데 어째서, 계속 그 사람 이름이 머릿속에 맴도는 건지…….","JPN":"でも、なぜあの人の名前が頭から離れないのか……","ENG":"But I can’t get that name out of my mind...","TWN":"但他的名字卻一直在我的腦海裡揮之不去……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"어째서 그 여자가 마지막 순간에 그를 지키기 위해 싸웠던 건지…….","JPN":"なぜあの女が最期に彼を守ろうと戦っていたのか……","ENG":"I don’t know why she fought until the end for him...","TWN":"為什麼她直到最後一刻都要為他拼命戰鬥呢……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"어째서…… 그 사람에 대해 더 알고 싶어지는 건지, 도저히 모르겠어요.","JPN":"なぜ……あの人のことをもっと知りたくなるのか、到底わかりません。","ENG":"And I don’t know why I want to get to know him better.","TWN":"到底為什麼……我會想知道更多有關他的事？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그건 자네가 리플레이서 퀸이었으면서…….","JPN":"それは、君がかつてリプレイサー・クイーンだったものの……","ENG":"That’s the proof that you were the Replacer Queen...","TWN":"這就證明，你雖然是克隆·女皇……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그녀와 다르다는 강력한 증거라네.","JPN":"彼女とは異なることを示す強力な証拠だ。","ENG":"And that you aren’t anymore.","TWN":"卻又和她不同。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"재판에 물증으로 제출할 수 없어서 아쉬울 따름이야.","JPN":"裁判に物証として出せないことが残念だがな。","ENG":"I’m very sorry that this can’t be used as a piece of evidence in your trial though.","TWN":"只是很可惜，這些無法成為呈堂證共。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사담은 이만 접어 두고 본론으로 들어가지.","JPN":"雑談はここまでにして、本題に入ろう。","ENG":"Enough of the chitchat, I’ll get to the point.","TWN":"先不說這些，我來找你是有其他事。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네가 협조해 줘야 할 일이 하나 더 생겼어.","JPN":"君の協力が必要な案件がもう一つある。","ENG":"There’s one more thing that I need your help with.","TWN":"又有一件事需要你幫忙。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"또…… 리플레이서와 관련된 일인가요?","JPN":"また……リプレイサー関連のことでしょうか？","ENG":"Is this about the Replacers again?","TWN":"又……是和克隆集團有關的事嗎？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 이 문서들은 우리가 리플레이서 신디케이트로부터 입수한 자료 중 일부라네.","JPN":"ああ、この文書は我々がリプレイサー・シンジケートから入手した資料の一部だ。","ENG":"Yes. These are some of the documents we got from the Replacer Syndicate.","TWN":"沒錯，這些文件是我們從克隆集團企業聯合組織那取得資料中的一部分。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"최근 우리 측 분석관들이 여기서 아주 흥미로운 정보를 하나 찾아냈지.","JPN":"最近、こちら側の分析官がこの中から非常に興味深い情報を一つ見つけてな。","ENG":"Our analysis officers found something very interesting in them.","TWN":"最近我們的分析人員最近發現一件很有趣的事。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>노바급 리액터</color>라던데, 뭔가 떠오르는 것 있나?","JPN":"<color=#ffd34c>ノヴァ級リアクター</color>だそうだ。何か心当たりはあるか？","ENG":"<color=#ffd34c>Nova-Class Reactor</color>. Do you remember anything about this?","TWN":"好像是叫<color=#ffd34c>諾瓦反應爐</color>，你有想起什麼嗎？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……아뇨. 아무것도 모르겠어요.","JPN":"……いいえ、何もわかりません。","ENG":"... No. Nothing.","TWN":"……沒有，我沒想起任何東西。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이나.","JPN":"ジェイナ。","ENG":"Jaina.","TWN":"婕娜。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"안토노프 대령님은 아시잖아요. 저는 리플레이서 퀸이 아니에요.","JPN":"アントノフ大佐はご存じでしょう。私はリプレイサー・クイーンではありません。","ENG":"Colonel, you know this. I’m not the Replacer Queen.","TWN":"安東諾夫上校您也很清楚，我不是克隆·女皇。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 퀸의 기억 같은 건……. 끔찍해서 떠올리고 싶지도 않아요.","JPN":"リプレイサー・クイーンの記憶なんて……おぞましくて思い出したくもありません。","ENG":"Her memory is just so horrible... I don’t even want to think about it.","TWN":"克隆·女皇那些可怕的記憶……我也完全不想想起來。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그런데도 저는, 그 여자 때문에 언제까지나 이런 곳에서……!","JPN":"なのに私は、あの女のせいでいつまでもこんなところに……！","ENG":"And yet I’m locked up in here because of that woman!","TWN":"再說，我被她害得不知道要在這裡關多久……！"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 자네로서는 억울하겠지.","JPN":"そうだな、君としてはやるせないだろう。","ENG":"Yes, it must be very frustrating for you.","TWN":"我知道你很委屈。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"뉴 오하이오에서 발견한 자네는 영락없이 겁에 질린 세 살짜리 꼬마였으니까.","JPN":"ニューオハイオで発見した君は、まるで恐怖に怯えていた3歳の子どものようだったからな。","ENG":"You were just like a three-year-old girl when you were found on the New Ohio.","TWN":"畢竟我們在新俄亥俄發現你時，你很明顯就是個面露驚恐的三歲小孩。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 제이나, 세상은 자네와 리플레이서 퀸이 다른 사람이란 사실을 믿지 않을 거야.","JPN":"だが、世界は君とリプレイサー・クイーンが別人だということを信じてくれないだろう。","ENG":"But Jaina, the world doesn’t believe that you and the Replacer Queen are different beings.","TWN":"不過婕娜，世人是不會相信你和克隆·女皇是截然不同兩個人的。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대다수는 불안해하겠지. 극단적인 자들은 자네를 없애는 걸로 안심하려고 할 테고.","JPN":"大体の者は不安に思うだろう。\\n君を消すことで平和を取り戻そうとする極端な人間もいるだろうし。","ENG":"Most of them are nervous. Some extremists will want to execute you just because it will make them feel better.","TWN":"大部分的人都很不安，甚至有極端分子想要除掉你來求安心。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그들이 자네를 이해하게 만들고 싶다면 자네도 그에 걸맞은 성의를 보여 줘야 해.","JPN":"彼らに君のことを理解させたければ、\\n君もそれにふさわしい誠意を見せなければならない。","ENG":"If you want them to understand that you’re not that woman, you have to do something about it.","TWN":"你若想讓大家理解你，就必須展現出足夠的誠意。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그건……. 저도 알고 있어요.","JPN":"それは……私もわかっています。","ENG":"I... I know that.","TWN":"那個……我也知道。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"알고 있는 것만으로는 부족해. 실천이 중요하지.","JPN":"わかっているだけでは足りない。肝心なのは実行することだ。","ENG":"Knowing is not enough. What they need is action.","TWN":"只是知道還不夠，實踐才是最重要的。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러고 보니 선물을 준다는 걸 깜빡했군. 나도 꽤 나이가 든 모양이야.","JPN":"ああ、そういえばプレゼントを渡すのを忘れていたな。私ももう老いぼれになったものだ。","ENG":"Oh, I forgot that I brought you a gift. I must be growing old.","TWN":"差點忘了，這是要送你的禮物，我果然是上了年紀了。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"이 주사위는…….","JPN":"このサイコロは……","ENG":"These dice...","TWN":"骰子……"},"stage":{"bg":"MAINSTREAM_802","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네의 헌신이 없었다면 난 아무것도 해낼 수 없었을 거야.","JPN":"君の献身がなければ、私は何も成し得なかっただろう。","ENG":"I couldn't have achieved anything without your tireless efforts.","TWN":"如果沒有你的犧牲，我大概什麼都做不到吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그동안 고마웠네.","JPN":"礼を言う。","ENG":"You have my thanks.","TWN":"一直以來非常謝謝你。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그리고...... 마지막까지 무운을 비네.","JPN":"そして……君の武運長久を祈るよ。","ENG":"And... Good luck, until the end.","TWN":"那麼……祝你武運昌隆。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"읏…….","JPN":"うっ……","ENG":"Ugh...","TWN":"唔……"},"stage":{"bg":"MAINSTREAM_802","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉의 소지품이야. 관리국이 보관하고 있던 걸 내 권한으로 반출해 왔지.","JPN":"ドミニークが持っていたものだ。管理局が保管していたのを私の権限で持ち出した。","ENG":"They are from Dominic. I had the authority to take them out from the Administration.","TWN":"那是多明尼克的東西，原本是管理局在保管的，我用我的權限把它弄出來。"},"stage":{"bg":"MAINSTREAM_802","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 퀸에게 도미닉이 어떤 의미였는지 궁금하다면 자네가 직접 알아내게.","JPN":"リプレイサー・クイーンにとってドミニークがどんな存在だったか、気になるなら自分で調べるといい。","ENG":"If you want to know what Dominic meant to the Replacer Queen, you’ll have to figure it out yourself.","TWN":"你不是想知道多明尼克對克隆·女皇的意義嗎？那就自己找出答案吧。"},"stage":{"bg":"MAINSTREAM_802","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나는 그런 이야기를 해 줄 수 있을 만큼 그 두 사람에 대해 잘 알지 못했던 모양이니까.","JPN":"私はそれを教えられるほど、あの二人のことをよく知っていたわけではないようだからな。","ENG":"I don’t think I knew them well enough to explain that to you.","TWN":"畢竟我對他們兩個不太認識，能告訴你的很有限。"},"stage":{"bg":"MAINSTREAM_802","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……고마워요. 제가 투정 부려도 받아 주셔서.","JPN":"……ありがとうございます、私のワガママを受け入れてくださって。","ENG":"Thank you... for listening to me.","TWN":"……謝謝你，容忍我的任性。"},"stage":{"bg":"MAINSTREAM_802","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"고마워할 것까지야.","JPN":"礼には及ばないさ。","ENG":"Don’t thank me.","TWN":"沒什麼好謝的。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이건 일종의 로비라네. 이번 일은 인류를 위해서라도 반드시 성공해야 하거든.","JPN":"これは一種のロビー活動だ。\\n今回の件は、人類のためにも必ず成功させなければならない。","ENG":"This is more like a bribe. I have to make it work, for the future of mankind.","TWN":"這算是一種遊說，因為這次的事關係到人類的未來，只許成功。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그럼 이 일만 성공하면…….","JPN":"では、今回の件さえ成功すれば……","ENG":"If I help you this time...","TWN":"那只要這件事成功……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"다른 분들도 제 성의를 알아 주실까요?","JPN":"他の方々も私の誠意をわかってくれるでしょうか？","ENG":"Do you think others will believe me too?","TWN":"大家就會明白我的誠意嗎？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇게 되도록 나 역시 항상 최선을 다하고 있다네.","JPN":"そうなるように私も常に最善を尽くしているんだ。","ENG":"I’m always doing my best to make it happen.","TWN":"我一直在為這件事努力。"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어떤가, 제이나? 대답은?","JPN":"どうだ、ジェイナ？　答えは？","ENG":"So what do you say, Jaina?","TWN":"怎麼樣，婕娜？你的回答是？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"노바급 리액터라는 거에 대해서……. 조금 더 자세히 말씀해 주세요.","JPN":"ノヴァ級リアクターについて……もう少し詳しく教えてください。","ENG":"Tell me more about the Nova-Class Reactor.","TWN":"諾瓦反應爐的事……可以再說清楚一點嗎？"},"stage":{"bg":"MAINSTREAM_801","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};